#!/bin/bash

set -e

SCRIPT_DIR=$( cd -- "$( dirname -- "${BASH_SOURCE[0]}" )" &> /dev/null && pwd )

VERSION=4.6.0

echo "This should be run from the root directory of the mongo repo"

BUILD_DIR=$SCRIPT_DIR/build
echo "Setting up $BUILD_DIR"
mkdir $BUILD_DIR -p && cd $BUILD_DIR

npm init --yes
npm install fast-check@$VERSION

cp $SCRIPT_DIR/shim.js $BUILD_DIR
cp $SCRIPT_DIR/bundle.mjs $BUILD_DIR

BUNDLED_LIB=fc-$VERSION-tmp.js
npx esbuild bundle.mjs \
  --bundle \
  --format=esm \
  --platform=browser \
  --target=es2018 \
  --minify \
  --outfile=$BUNDLED_LIB

OUTFILE=$BUILD_DIR/fc-$VERSION.js
echo -e "// This file was auto-generated by $0\n" | cat - shim.js $BUNDLED_LIB > $OUTFILE

npx prettier --write $OUTFILE


